"use client";

import React, { useState } from 'react';
import { useRouter } from 'next/navigation';
import { JobPost } from '@/types/admin';
import { useAdmin } from '@/components/admin/AdminProvider';
import { Eye, ArrowLeft, Loader2 } from 'lucide-react';
import JobPreviewModal from './JobPreviewModal';

interface JobFormProps {
    initialData?: JobPost;
    isEditing?: boolean;
}

const EMPTY_JOB: Omit<JobPost, 'id' | 'postedAt' | 'updatedAt' | 'applicationCount' | 'views'> = {
    title: '',
    department: '',
    category: '',
    location: { city: '', country: '', latitude: 0, longitude: 0 },
    workMode: 'Onsite',
    employmentType: 'Full-time',
    experienceRange: { min: 0, max: 0 },
    salary: { min: 0, max: 0, currency: 'INR', period: 'Yearly' },
    summary: '',
    description: '',
    responsibilities: [],
    requirements: [],
    skills: [],
    status: 'Draft',
};

export default function JobForm({ initialData, isEditing = false }: JobFormProps) {
    const router = useRouter();
    const { addJob, updateJob } = useAdmin();
    const [loading, setLoading] = useState(false);
    const [formData, setFormData] = useState<JobPost | any>(initialData || EMPTY_JOB);
    const [newSkill, setNewSkill] = useState('');
    const [showPreview, setShowPreview] = useState(false);

    const handleChange = (field: keyof JobPost, value: string | number | boolean) => {
        setFormData((prev: JobPost) => ({ ...prev, [field]: value }));
    };

    const handleNestedChange = (parent: keyof JobPost, field: string, value: string | number) => {
        setFormData((prev: JobPost) => ({
            ...prev,
            [parent]: { ...(prev[parent as keyof JobPost] as object), [field]: value }
        }));
    };

    const handleArrayAdd = (field: 'skills' | 'responsibilities' | 'requirements', value: string) => {
        if (!value.trim()) return;
        setFormData((prev: JobPost) => ({
            ...prev,
            [field]: [...(prev[field as keyof JobPost] as string[]), value]
        }));
        if (field === 'skills') setNewSkill('');
    };

    const handleArrayRemove = (field: 'skills' | 'responsibilities' | 'requirements', index: number) => {
        setFormData((prev: JobPost) => ({
            ...prev,
            [field]: (prev[field as keyof JobPost] as string[]).filter((_: string, i: number) => i !== index)
        }));
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);

        // Simulate API call
        await new Promise(resolve => setTimeout(resolve, 1000));

        if (isEditing && initialData) {
            updateJob(initialData.id, formData);
        } else {
            addJob(formData);
        }

        setLoading(false);
        router.push('/admin/jobs');
    };

    return (
        <>
            <form onSubmit={handleSubmit} className="space-y-8">
                {/* Header Actions */}
                <div className="flex items-center justify-between sticky top-16 bg-gray-50 py-4 z-30">
                    <div className="flex items-center gap-4">
                        <button type="button" onClick={() => router.back()} className="p-2 hover:bg-gray-200 rounded-full text-gray-500">
                            <ArrowLeft className="w-5 h-5" />
                        </button>
                        <h2 className="text-xl font-bold text-gray-900">{isEditing ? 'Edit Job' : 'Create New Job'}</h2>
                    </div>
                    <div className="flex items-center gap-3">
                        <button
                            type="button"
                            onClick={() => setShowPreview(true)}
                            className="px-4 py-2 bg-white border border-gray-200 rounded-lg text-gray-700 font-medium hover:bg-gray-50 flex items-center gap-2"
                        >
                            <Eye className="w-4 h-4" /> Preview
                        </button>
                        <button
                            type="submit"
                            disabled={loading}
                            className="px-6 py-2 bg-blue-500 text-white rounded-lg font-bold hover:bg-blue-600 shadow-md flex items-center gap-2 disabled:opacity-70"
                        >
                            {loading && <Loader2 className="w-4 h-4 animate-spin" />}
                            {isEditing ? 'Save Changes' : 'Create Job'}
                        </button>
                    </div>
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                    {/* Main Content */}
                    <div className="lg:col-span-2 space-y-8">
                        {/* Basic Info */}
                        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 space-y-6">
                            <h3 className="font-bold text-gray-800 text-lg border-b border-gray-100 pb-3">Basic Information</h3>

                            <div className="grid grid-cols-2 gap-6">
                                <div className="col-span-2">
                                    <label className="block text-sm font-medium text-gray-700 mb-1">Job Title *</label>
                                    <input
                                        type="text"
                                        required
                                        className="w-full px-4 py-2 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-100 focus:border-blue-400 outline-none"
                                        value={formData.title}
                                        onChange={(e) => handleChange('title', e.target.value)}
                                    />
                                </div>

                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">Department</label>
                                    <input
                                        type="text"
                                        className="w-full px-4 py-2 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-100 focus:border-blue-400 outline-none"
                                        value={formData.department}
                                        onChange={(e) => handleChange('department', e.target.value)}
                                    />
                                </div>

                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">Category</label>
                                    <select
                                        className="w-full px-4 py-2 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-100 focus:border-blue-400 outline-none bg-white"
                                        value={formData.category}
                                        onChange={(e) => handleChange('category', e.target.value)}
                                    >
                                        <option value="">Select Category</option>
                                        <option value="Engineering">Engineering</option>
                                        <option value="Design">Design</option>
                                        <option value="Product">Product</option>
                                        <option value="Sales">Sales</option>
                                        <option value="Marketing">Marketing</option>
                                    </select>
                                </div>
                            </div>
                        </div>

                        {/* Description */}
                        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 space-y-6">
                            <h3 className="font-bold text-gray-800 text-lg border-b border-gray-100 pb-3">Job Description</h3>

                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Short Summary (for cards)</label>
                                <textarea
                                    className="w-full px-4 py-2 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-100 focus:border-blue-400 outline-none h-24"
                                    value={formData.summary}
                                    onChange={(e) => handleChange('summary', e.target.value)}
                                />
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Full Description (HTML Supported)</label>
                                <textarea
                                    className="w-full px-4 py-2 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-100 focus:border-blue-400 outline-none h-64 font-mono text-sm"
                                    value={formData.description}
                                    onChange={(e) => handleChange('description', e.target.value)}
                                    placeholder="<p>Enter detailed description...</p>"
                                />
                            </div>
                        </div>
                    </div>

                    {/* Sidebar Controls */}
                    <div className="space-y-6">
                        {/* Status */}
                        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 space-y-4">
                            <h3 className="font-bold text-gray-800 text-lg">Status</h3>
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-2">Publish Status</label>
                                <select
                                    className="w-full px-4 py-2 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-100 focus:border-blue-400 outline-none bg-white"
                                    value={formData.status}
                                    onChange={(e) => handleChange('status', e.target.value)}
                                >
                                    <option value="Draft">Draft</option>
                                    <option value="Published">Published</option>
                                    <option value="Closed">Closed</option>
                                </select>
                            </div>
                        </div>

                        {/* Location */}
                        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 space-y-4">
                            <h3 className="font-bold text-gray-800 text-lg">Location</h3>
                            <div className="space-y-3">
                                <div>
                                    <label className="block text-xs font-medium text-gray-500 mb-1">City</label>
                                    <input
                                        type="text"
                                        className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm"
                                        value={formData.location.city}
                                        onChange={(e) => handleNestedChange('location', 'city', e.target.value)}
                                    />
                                </div>
                                <div>
                                    <label className="block text-xs font-medium text-gray-500 mb-1">Country</label>
                                    <input
                                        type="text"
                                        className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm"
                                        value={formData.location.country}
                                        onChange={(e) => handleNestedChange('location', 'country', e.target.value)}
                                    />
                                </div>
                                <div className="grid grid-cols-2 gap-2">
                                    <div>
                                        <label className="block text-xs font-medium text-gray-500 mb-1">Latitude</label>
                                        <input
                                            type="number"
                                            step="0.0001"
                                            className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm"
                                            value={formData.location.latitude}
                                            onChange={(e) => handleNestedChange('location', 'latitude', parseFloat(e.target.value))}
                                        />
                                    </div>
                                    <div>
                                        <label className="block text-xs font-medium text-gray-500 mb-1">Longitude</label>
                                        <input
                                            type="number"
                                            step="0.0001"
                                            className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm"
                                            value={formData.location.longitude}
                                            onChange={(e) => handleNestedChange('location', 'longitude', parseFloat(e.target.value))}
                                        />
                                    </div>
                                </div>
                            </div>
                        </div>

                        {/* Work Details */}
                        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 space-y-4">
                            <h3 className="font-bold text-gray-800 text-lg">Work Details</h3>

                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-2">Work Mode</label>
                                <div className="flex gap-2">
                                    {['Remote', 'Hybrid', 'Onsite'].map(mode => (
                                        <button
                                            key={mode}
                                            type="button"
                                            onClick={() => handleChange('workMode', mode)}
                                            className={`flex-1 py-1.5 text-xs font-medium rounded-md border ${formData.workMode === mode
                                                ? 'bg-blue-50 border-blue-500 text-blue-700'
                                                : 'bg-white border-gray-200 text-gray-600 hover:bg-gray-50'
                                                }`}
                                        >
                                            {mode}
                                        </button>
                                    ))}
                                </div>
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-2">Employment</label>
                                <select
                                    className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm outline-none bg-white"
                                    value={formData.employmentType}
                                    onChange={(e) => handleChange('employmentType', e.target.value)}
                                >
                                    <option value="Full-time">Full-time</option>
                                    <option value="Part-time">Part-time</option>
                                    <option value="Contract">Contract</option>
                                    <option value="Internship">Internship</option>
                                </select>
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-2">Salary Range ({formData.salary.currency})</label>
                                <div className="flex gap-2 items-center">
                                    <input
                                        type="number"
                                        placeholder="Min"
                                        className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm"
                                        value={formData.salary.min}
                                        onChange={(e) => handleNestedChange('salary', 'min', parseInt(e.target.value))}
                                    />
                                    <span className="text-gray-400">-</span>
                                    <input
                                        type="number"
                                        placeholder="Max"
                                        className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm"
                                        value={formData.salary.max}
                                        onChange={(e) => handleNestedChange('salary', 'max', parseInt(e.target.value))}
                                    />
                                </div>
                            </div>
                        </div>

                        {/* Skills */}
                        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 space-y-4">
                            <h3 className="font-bold text-gray-800 text-lg">Skills</h3>
                            <div className="flex gap-2">
                                <input
                                    type="text"
                                    placeholder="Add skill..."
                                    className="flex-1 px-3 py-2 border border-gray-200 rounded-lg text-sm"
                                    value={newSkill}
                                    onChange={(e) => setNewSkill(e.target.value)}
                                    onKeyDown={(e) => e.key === 'Enter' && (e.preventDefault(), handleArrayAdd('skills', newSkill))}
                                />
                                <button
                                    type="button"
                                    onClick={() => handleArrayAdd('skills', newSkill)}
                                    className="px-3 py-2 bg-gray-100 rounded-lg text-sm font-medium text-gray-700 hover:bg-gray-200"
                                >
                                    Add
                                </button>
                            </div>
                            <div className="flex flex-wrap gap-2">
                                {formData.skills.map((skill: string, i: number) => (
                                    <span key={i} className="inline-flex items-center gap-1 px-2 py-1 bg-blue-50 text-blue-700 text-xs rounded-md">
                                        {skill}
                                        <button type="button" onClick={() => handleArrayRemove('skills', i)} className="hover:text-blue-900">×</button>
                                    </span>
                                ))}
                            </div>
                        </div>
                    </div>
                </div>
            </form>

            <JobPreviewModal
                isOpen={showPreview}
                onClose={() => setShowPreview(false)}
                job={{ ...formData, id: 'preview', postedAt: new Date().toISOString() }}
            />
        </>
    );
}

"use client";

import React, { useState } from 'react';
import Link from 'next/link';
import { JobPost } from '@/types/admin';
import { Eye, Edit2, Trash2, CheckCircle } from 'lucide-react';
import { useAdmin } from '@/components/admin/AdminProvider';

export default function JobsDataTable({ jobs }: { jobs: JobPost[] }) {
    const { deleteJob, updateJob } = useAdmin();
    const [filterStatus, setFilterStatus] = useState<string>('All');
    const [searchQuery, setSearchQuery] = useState('');

    const filteredJobs = jobs.filter(job => {
        const matchesStatus = filterStatus === 'All' || job.status === filterStatus;
        const matchesSearch = job.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
            job.department.toLowerCase().includes(searchQuery.toLowerCase());
        return matchesStatus && matchesSearch;
    });

    const handleDelete = (id: string) => {
        if (confirm('Are you sure you want to delete this job?')) {
            deleteJob(id);
        }
    };

    return (
        <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
            {/* Filters Toolbar */}
            <div className="p-4 border-b border-gray-100 flex flex-col sm:flex-row sm:items-center justify-between gap-4">
                <div className="flex items-center gap-2">
                    {['All', 'Published', 'Draft', 'Closed'].map(status => (
                        <button
                            key={status}
                            onClick={() => setFilterStatus(status)}
                            className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-colors ${filterStatus === status
                                ? 'bg-blue-50 text-blue-600'
                                : 'text-gray-500 hover:bg-gray-50'
                                }`}
                        >
                            {status}
                        </button>
                    ))}
                </div>
                <div className="relative">
                    <input
                        type="text"
                        placeholder="Search jobs..."
                        className="pl-4 pr-4 py-2 border border-gray-200 rounded-lg text-sm w-full sm:w-64 focus:outline-none focus:ring-2 focus:ring-blue-100 focus:border-blue-400"
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                    />
                </div>
            </div>

            {/* Table */}
            <div className="overflow-x-auto">
                <table className="w-full text-sm text-left">
                    <thead className="bg-gray-50 text-gray-500 font-medium border-b border-gray-100">
                        <tr>
                            <th className="px-6 py-3">Job Title</th>
                            <th className="px-6 py-3">Location</th>
                            <th className="px-6 py-3">Type</th>
                            <th className="px-6 py-3">Status</th>
                            <th className="px-6 py-3">Applications</th>
                            <th className="px-6 py-3">Date</th>
                            <th className="px-6 py-3 text-right">Actions</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-100">
                        {filteredJobs.length > 0 ? (
                            filteredJobs.map((job) => (
                                <tr key={job.id} className="hover:bg-gray-50 transition-colors group">
                                    <td className="px-6 py-4">
                                        <p className="font-medium text-gray-900">{job.title}</p>
                                        <p className="text-xs text-gray-500">{job.department}</p>
                                    </td>
                                    <td className="px-6 py-4 text-gray-500">
                                        {job.location.city}, {job.location.country}
                                    </td>
                                    <td className="px-6 py-4 text-gray-500">
                                        <span className="block">{job.employmentType}</span>
                                        <span className="text-xs text-gray-400">{job.workMode}</span>
                                    </td>
                                    <td className="px-6 py-4">
                                        <span className={`px-2.5 py-1 rounded-full text-xs font-semibold inline-flex items-center gap-1 ${job.status === 'Published' ? 'bg-green-50 text-green-700' :
                                            job.status === 'Draft' ? 'bg-yellow-50 text-yellow-700' :
                                                'bg-gray-100 text-gray-600'
                                            }`}>
                                            {job.status === 'Published' && <CheckCircle className="w-3 h-3" />}
                                            {job.status}
                                        </span>
                                    </td>
                                    <td className="px-6 py-4 text-gray-500 font-medium">
                                        {job.applicationCount}
                                    </td>
                                    <td className="px-6 py-4 text-gray-500 text-xs">
                                        Posted: {new Date(job.postedAt).toLocaleDateString('en-US')}
                                    </td>
                                    <td className="px-6 py-4 text-right">
                                        <div className="flex items-center justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                                            <Link href={`/admin/jobs/${job.id}`} className="text-gray-400 hover:text-blue-500 p-1" title="View">
                                                <Eye className="w-4 h-4" />
                                            </Link>
                                            <Link href={`/admin/jobs/${job.id}/edit`} className="text-gray-400 hover:text-blue-500 p-1" title="Edit">
                                                <Edit2 className="w-4 h-4" />
                                            </Link>
                                            <button onClick={() => handleDelete(job.id)} className="text-gray-400 hover:text-red-500 p-1" title="Delete">
                                                <Trash2 className="w-4 h-4" />
                                            </button>
                                        </div>
                                    </td>
                                </tr>
                            ))
                        ) : (
                            <tr>
                                <td colSpan={7} className="px-6 py-12 text-center text-gray-500">
                                    No jobs found matching your filters.
                                </td>
                            </tr>
                        )}
                    </tbody>
                </table>
            </div>

            {/* Pagination Footer (Mock) */}
            <div className="px-6 py-4 border-t border-gray-100 flex items-center justify-between text-sm text-gray-500">
                <p>Showing {filteredJobs.length} results</p>
                <div className="flex gap-2">
                    <button className="px-3 py-1 border border-gray-200 rounded hover:bg-gray-50 disabled:opacity-50" disabled>Previous</button>
                    <button className="px-3 py-1 border border-gray-200 rounded hover:bg-gray-50 disabled:opacity-50" disabled>Next</button>
                </div>
            </div>
        </div>
    );
}

"use client";

import React from "react";
import Link from "next/link";
import { usePathname, useRouter } from "next/navigation";
import Image from "next/image";
import { motion } from "framer-motion";
import { fadeUp, staggerContainer, viewportOnce } from "@/animations";

// Helper function to handle navigation with smooth scroll
const handleNavClick = (href: string, router: { push: (href: string) => void }, pathname: string, e?: React.MouseEvent) => {
  if (e) e.preventDefault();

  // If href starts with #, it's a section anchor
  if (href.startsWith("#")) {
    // If we're on the home page or ninexFold page, just scroll to the section
    if (pathname === "/" || pathname === "/ninexFold" || pathname.startsWith("/ninexFold/")) {
      const element = document.querySelector(href);
      if (element) {
        element.scrollIntoView({ behavior: "smooth", block: "start" });
      }
    } else {
      // Navigate to home page first, then scroll after navigation
      router.push(`/ninexFold${href}`);
      // Wait a bit for navigation, then scroll
      setTimeout(() => {
        const element = document.querySelector(href);
        if (element) {
          element.scrollIntoView({ behavior: "smooth", block: "start" });
        }
      }, 100);
    }
  } else {
    // Regular navigation - let Next.js handle it
    router.push(href);
  }
};

const footerColumns = [
  {
    title: "Who We Are",
    links: [
      { name: "Purpose Led", href: "#" },
      { name: "Performance Driven", href: "#" },
      { name: "Future Ready", href: "#" },
      { name: "Leadership", href: "#" },
      { name: "Our History", href: "#" },
    ],
  },
  {
    title: "What We Do",
    links: [
      { name: "Industries", href: "#" },
      { name: "Our Brands", href: "/ninexFold/global-presence" },
      { name: "Global Presence", href: "/ninexFold/global-presence" },
    ],
  },
  {
    title: "Careers",
    links: [
      { name: "Find A Job", href: "#" },
      { name: "Leadership Programs", href: "#" },
      { name: "Tech Opportunities", href: "#" },
    ],
  },
];

const legalLinks = [
  { name: "Terms of use", href: "/legal/terms-of-use" },
  { name: "Disclaimer", href: "/legal/disclaimer" },
  { name: "Privacy Policy", href: "/legal/privacy-policy" },
  { name: "Sitemap", href: "/legal/sitemap" },
  { name: "Contact Us", href: "/legal/contact-us" },
];

export default function Footer() {
  const router = useRouter();
  const pathname = usePathname();

  return (
    <footer className="relative bg-gradient-to-b from-[#0A1628] to-[#1A2840] text-white py-8 sm:py-12 md:py-16 px-4 sm:px-6 md:px-8 lg:px-16 xl:px-24 overflow-hidden">
      {/* Background glow */}
      <div className="absolute inset-0 bg-brand-gradient opacity-20 blur-3xl" />

      <div className="relative max-w-7xl mx-auto">
        {/* Top Grid */}
        <motion.div
          className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8 sm:gap-10 md:gap-12 lg:gap-8 mb-8 sm:mb-12 md:mb-16"
          initial="hidden"
          whileInView="show"
          viewport={viewportOnce}
          variants={staggerContainer}
        >
          {/* Brand */}
          <motion.div
            className="space-y-4 sm:space-y-5 md:space-y-6"
            variants={fadeUp}
          >
            <Image
              src="https://api.builder.io/api/v1/image/assets/TEMP/e17d68d8e248bb0b5749fd61ee6f92a4054967ff?width=490"
              alt="NineXGroup"
              width={490}
              height={40}
              className="h-6 sm:h-7 w-auto"
              priority
            />
            <p className="text-white/90 font-be-vietnam text-sm sm:text-base font-light leading-relaxed max-w-sm">
              Stay updated with our latest cleaning tips, service updates, and helpful articles on maintaining a spotless home.
            </p>
          </motion.div>

          {/* Who We Are */}
          <motion.div
            className="space-y-5 sm:space-y-7 md:space-y-9 md:ml-32"
            variants={fadeUp}
          >
            <h3 className="text-white font-be-vietnam text-lg sm:text-xl font-bold capitalize">
              Who We Are
            </h3>
