        <div className="flex flex-col sm:flex-row items-center sm:items-center space-y-4 sm:space-y-0 pt-6 sm:pt-8 justify-between border-t border-white/10 w-full gap-4 sm:gap-0">
          <nav className="flex flex-wrap items-center justify-center sm:justify-start [font-family:'Be_Vietnam',Helvetica] font-normal text-white text-xs sm:text-sm md:text-base tracking-[0] leading-[19.2px] gap-2 sm:gap-0">
            {[
              { name: "Terms of use", href: "/legal/terms-of-use" },
