export default function Navigation() {
  const router = useRouter();
  const pathname = usePathname();
  const [activeIndex, setActiveIndex] = useState(0);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [openDropdownIndex, setOpenDropdownIndex] = useState<number | null>(null);
  const [expandedMobileIndex, setExpandedMobileIndex] = useState<number | null>(null);
  const [hoveredCategoryIndex, setHoveredCategoryIndex] = useState<number | null>(null);
  const [hoveredSubCategoryIndex, setHoveredSubCategoryIndex] = useState<{ parent: number; child: number } | null>(null);
  const [level3Items, setLevel3Items] = useState<NavigationItem[] | null>(null);

  const dropdownRefs = useRef<(HTMLDivElement | null)[]>([]);

  const handleLinkClick = (index: number, href: string, e?: React.MouseEvent) => {
    if (e) e.preventDefault();
    setActiveIndex(index);
    setIsMobileMenuOpen(false); // Close mobile menu when a link is clicked

    // Handle navigation
    if (href.startsWith("#")) {
      // Check if href is a valid selector (not just "#")
      if (href === "#") {
        // Just "#" means no action, likely a placeholder link
        return;
      }

      // Hash link - scroll to section
      if (pathname === "/" || pathname === "/ninexFold" || pathname.startsWith("/ninexFold/")) {
        // On home/ninexFold page, scroll to section
        const element = document.querySelector(href);
        if (element) {
          element.scrollIntoView({ behavior: "smooth", block: "start" });
        }
      } else {
        // Navigate to home page with hash
        router.push(`/ninexFold${href}`);
        // Scroll after navigation
        setTimeout(() => {
          const element = document.querySelector(href);
          if (element) {
            element.scrollIntoView({ behavior: "smooth", block: "start" });
          }
        }, 100);
      }
    } else {
      // Regular page navigation
      router.push(href);
    }
  };

  const toggleMobileMenu = (e?: React.MouseEvent) => {
    if (e) e.preventDefault();
    setIsMobileMenuOpen(!isMobileMenuOpen);
  };

  const handleDropdownToggle = (index: number, e: React.MouseEvent) => {
    e.stopPropagation();
    setOpenDropdownIndex(openDropdownIndex === index ? null : index);
  };

  const handleChildClick = (childHref: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setOpenDropdownIndex(null);
    setIsMobileMenuOpen(false);
    handleLinkClick(-1, childHref, e);
  };

  const toggleMobileDropdown = (index: number, e: React.MouseEvent) => {
    e.stopPropagation();
    setExpandedMobileIndex(expandedMobileIndex === index ? null : index);
  };

  // Close dropdown when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (openDropdownIndex !== null) {
        const dropdownRef = dropdownRefs.current[openDropdownIndex];
        if (dropdownRef && !dropdownRef.contains(event.target as Node)) {
          setOpenDropdownIndex(null);
          setHoveredCategoryIndex(null);
          setHoveredSubCategoryIndex(null);
        }
      }
    };

    document.addEventListener("mousedown", handleClickOutside);
    return () => {
      document.removeEventListener("mousedown", handleClickOutside);
    };
  }, [openDropdownIndex]);

  return (
    <nav className="sticky top-0 left-0 w-full flex 
                    items-center 
                    justify-between
                    px-4 sm:px-6 md:px-8 lg:px-[135px]
                    h-[88px]
                    bg-white z-[60]"
    >
      {/* Logo */}
      <div className="w-[214px] flex items-center">
        <Image
          width={214}
          height={27}
          alt="NinexGroup Logo"
          src="https://c.animaapp.com/mja25s0wQvjgBd/img/frame-21-1.png"
          className="block h-[27px] w-auto"
          unoptimized
        />
      </div>

      {/* Desktop Navigation Links - Hidden on mobile */}
      <div className="hidden lg:flex relative items-center gap-[29px] h-full">
        {navigationItems.map((item, index) => {
          const isActive = activeIndex === index;
          const hasChildren = item.children && item.children.length > 0;
          const isDropdownOpen = openDropdownIndex === index;

          return (
            <div
              key={index}
              className="relative h-full flex items-center"
              ref={(el) => { dropdownRefs.current[index] = el; }}
              onMouseEnter={() => hasChildren && setOpenDropdownIndex(index)}
              onMouseLeave={() => {
                if (!hasChildren) {
                  setOpenDropdownIndex(null);
                }
              }}
            >

              <div className="flex items-center gap-1 cursor-pointer">
                <div
                  onClick={(e) => handleLinkClick(index, item.href, e)}
                  className={`transition-all duration-300 relative ${isActive || isDropdownOpen
                    ? "bg-[linear-gradient(127deg,#12D4FF,#1959FA)] text-transparent bg-clip-text font-medium"
                    : "text-[#4d4d4d] hover:text-[#1959FA]"
                    }`}
                >
                  {item.label}
                </div>

                {hasChildren && (
                  <ChevronDown
                    className={`w-4 h-4 transition-transform ${isDropdownOpen ? "rotate-180 text-[#1959FA]" : "text-[#4d4d4d]"
                      }`}
                  />
                )}
              </div>

              {/* Horizontal line below active navigation link - matches text width exactly, sticks to bottom of nav */}
              {(isActive || isDropdownOpen) && !hasChildren && (
                <div
                  className="absolute bottom-[-36.5px] left-0 h-[3px] w-full transition-all duration-300"
                  style={{
                    background: "linear-gradient(92deg, #12D4FF 22.22%, #1959FA 88.58%)",
                  }}
                />
              )}

              {/* Horizontal line below navigation link when dropdown is open */}
              {isDropdownOpen && hasChildren && (
                <div
                  className="absolute bottom-[-36.5px] left-0 h-[3px] w-full transition-all duration-300"
                  style={{
                    background: "linear-gradient(92deg, #12D4FF 22.22%, #1959FA 88.58%)",
                  }}
                />
              )}

              {/* Desktop Mega-Menu Dropdown */}
              {hasChildren && (
                <AnimatePresence>
                  {isDropdownOpen && (
                    <motion.div
                      initial={{ opacity: 0, y: -10 }}
                      animate={{ opacity: 1, y: 0 }}
                      exit={{ opacity: 0, y: -10 }}
                      transition={{ duration: 0.2 }}
                      className="fixed top-[88px] left-0 w-full bg-[#F5F5F5] shadow-2xl z-50"
                      style={{
                        left: '0',
                        transform: 'translateX(0)',
                      }}
                      onMouseEnter={() => setOpenDropdownIndex(index)}
                      onMouseLeave={() => {
                        setOpenDropdownIndex(null);
                        setHoveredCategoryIndex(null);
                        setHoveredSubCategoryIndex(null);
                      }}
                    >
                      {/* Gradient top border */}
                      <div
                        className="h-[3px] w-full"
                        style={{
                          background: "linear-gradient(92deg, #12D4FF 22.22%, #1959FA 88.58%)",
                        }}
                      />
                      <div className="flex w-full">
                        {/* LEFT INFO PANEL */}
                        <div className="w-[360px] bg-white p-10 border-r border-[#E5E7EB]">
                          {item.leftPanel?.title && (
                            <h2 className="text-2xl font-semibold text-[#0A0A0A] mb-6">
                              {item.leftPanel.title}
                            </h2>
                          )}
                          {item.leftPanel?.stats && (
                            <div className="space-y-6">
                              {item.leftPanel.stats.map((stat, i) => (
                                <div key={i} className="flex justify-between text-lg">
                                  <span className="bg-[linear-gradient(127deg,#12D4FF,#1959FA)] text-transparent bg-clip-text font-semibold">
                                    {stat.value}
                                  </span>
                                  <span>{stat.label}</span>
                                </div>
                              ))}
                            </div>
                          )}

                          {item.leftPanel?.description && (
                            <p className="text-gray-700 leading-relaxed">
                              {item.leftPanel.description}
                            </p>
                          )}

                          {item.leftPanel?.hashtag && (
                            <p className="mt-4 font-medium">{item.leftPanel.hashtag}</p>
                          )}
                        </div>
                        {/* RIGHT MENU — CENTERED */}
                        <div className="flex flex-1 justify-center">
                          <div className="max-w-[1200px] flex w-full">
                            {/* Column 1: Main Categories */}
                            <div className="w-[260px] border-r border-gray-300 p-6">
                              {item.children?.map((child, childIndex) => {
                                const hasSubChildren = child.children && child.children.length > 0;
                                const isCategoryHovered = hoveredCategoryIndex === childIndex;

                                return (
                                  <div
                                    key={childIndex}
                                    className={childIndex < (item.children?.length || 0) - 1 ? "pb-3 mb-3 border-b border-gray-300" : ""}
                                    onMouseEnter={() => {
                                      setHoveredCategoryIndex(childIndex);
                                      setHoveredSubCategoryIndex(null);
                                      setLevel3Items(null);
                                    }}
                                  >
                                    <div
                                      onClick={(e) => {
                                        if (!hasSubChildren) {
                                          handleChildClick(child.href, e);
                                        }
                                      }}
                                      className={`flex items-center justify-between cursor-pointer transition-colors ${isCategoryHovered
                                        ? "text-[#1959FA]"
                                        : "text-[#0A0A0A] hover:text-[#1959FA]"
                                        }`}
                                    >
                                      <span className={`text-sm font-medium ${isCategoryHovered ? "underline decoration-2 underline-offset-4" : ""}`}>
                                        {child.label}
                                      </span>
                                      {hasSubChildren && (
                                        <ChevronRight className={`w-4 h-4 transition-transform ${isCategoryHovered ? "text-[#1959FA]" : "text-[#4d4d4d]"}`} />
                                      )}
                                    </div>
                                  </div>
                                );
                              })}
                            </div>

                            {/* Column 2: Sub-Categories */}
                            <div className="w-[320px] border-r border-gray-300 p-6">
                              {hoveredCategoryIndex !== null && item.children && item.children[hoveredCategoryIndex] && item.children[hoveredCategoryIndex].children && (
                                <div className="space-y-0">
                                  {(item.children[hoveredCategoryIndex].children || []).map((subChild: NavigationItem, subIndex: number) => {
                                    const hasNestedChildren = subChild.children && subChild.children.length > 0;
                                    const isSubHovered = hoveredSubCategoryIndex?.parent === hoveredCategoryIndex && hoveredSubCategoryIndex?.child === subIndex;

                                    return (
                                      <div
                                        key={subIndex}
                                        className="relative group"
                                        onMouseEnter={() => {
                                          setHoveredSubCategoryIndex({ parent: hoveredCategoryIndex, child: subIndex });
                                          setLevel3Items(hasNestedChildren ? subChild.children || null : null);
                                        }}
                                      >
                                        <div
                                          onClick={(e) => {
                                            if (!hasNestedChildren) {
                                              handleChildClick(subChild.href, e);
                                            }
                                          }}
                                          className={`flex items-center justify-between py-2 px-3 cursor-pointer transition-colors rounded ${isSubHovered
                                            ? "bg-white text-[#1959FA] shadow-sm"
                                            : "text-[#0A0A0A] hover:bg-white hover:text-[#1959FA]"
                                            }`}
                                        >
                                          <span className="text-sm">{subChild.label}</span>
                                          {hasNestedChildren && (
                                            <ChevronRight className={`w-4 h-4 ${isSubHovered ? "text-[#1959FA]" : "text-[#4d4d4d]"}`} />
                                          )}
                                        </div>
                                      </div>
                                    );
                                  })}
                                </div>
                              )}
                            </div>
                            {/* Column 3: Sub-Sub Categories */}
                            <div className="flex-1 p-6">
                              {level3Items ? (
                                level3Items.map((item, index) => (
                                  <div
                                    key={index}
                                    onClick={(e) => handleChildClick(item.href, e)}
                                    className="px-3 py-2 text-sm cursor-pointer rounded
                                              text-[#0A0A0A] hover:bg-gray-50 hover:text-[#1959FA]
                                              transition-colors"
                                  >
                                    {item.label}
                                  </div>
                                ))
                              ) : (
                                <div className="text-sm text-gray-400">
                                </div>
                              )}
                            </div>
                          </div>
                        </div>
                      </div>
                    </motion.div>
                  )}
                </AnimatePresence>
              )}
            </div>
          );
        })}
      </div>

      {/* Desktop Get a quote button - Hidden on mobile */}
      <motion.button
        type="button"
        onClick={(e) => {
          e.preventDefault();
          router.push("/legal/contact-us");
        }}
        className="hidden lg:flex items-center justify-center
                  h-[44px]
                  bg-[linear-gradient(33deg,rgb(18,212,255)_0%,rgb(25,89,250)_100%)]
                  px-6 rounded-md"
        whileHover={buttonHover}
        whileTap={buttonTap}
      >
        Get a quote
      </motion.button>

      {/* Mobile Hamburger Icon */}
      <button
        type="button"
        onClick={(e) => toggleMobileMenu(e)}
        className="lg:hidden flex items-center justify-center w-10 h-10 text-[#4d4d4d] hover:text-[#666666] transition-colors"
        aria-label="Toggle menu"
      >
        {isMobileMenuOpen ? (
          <X className="w-6 h-6" />
        ) : (
          <Menu className="w-6 h-6" />
        )}
      </button>

      {/* Mobile Menu Overlay */}
      {isMobileMenuOpen && (
        <>
          {/* Backdrop */}
          <div
            className="fixed inset-0 bg-black/50 z-40 lg:hidden"
            onClick={(e) => {
              e.preventDefault();
              setIsMobileMenuOpen(false);
            }}
          />

          {/* Mobile Menu */}
          <div className="fixed top-0 right-0 h-full w-[280px] sm:w-[320px] bg-white shadow-2xl z-50 lg:hidden transform transition-transform duration-300 ease-in-out">
            <div className="flex flex-col h-full">
              {/* Mobile Menu Header */}
              <div className="flex items-center justify-between p-4 border-b border-gray-200">
                <div className="w-[150px] h-6">
                  <Image
                    width={214}
                    height={27}
                    alt="NinexGroup Logo"
                    src="https://c.animaapp.com/mja25s0wQvjgBd/img/frame-21-1.png"
                    className="w-full h-auto max-h-[27px]"
                    unoptimized
                  />
                </div>
                <button
                  type="button"
                  onClick={(e) => {
                    e.preventDefault();
                    setIsMobileMenuOpen(false);
                  }}
                  className="w-10 h-10 flex items-center justify-center text-[#4d4d4d] hover:text-[#666666] transition-colors"
                  aria-label="Close menu"
                >
                  <X className="w-6 h-6" />
                </button>
              </div>

              {/* Mobile Navigation Links */}
              <div className="flex-1 overflow-y-auto py-6">
                <div className="flex flex-col">
                  {navigationItems.map((item, index) => {
                    const isActive = activeIndex === index;
                    const hasChildren = item.children && item.children.length > 0;
                    const isExpanded = expandedMobileIndex === index;

                    return (
                      <div
                        key={index}
                        className="relative"
                      >
                        <div
                          className="flex items-center justify-between"
                        >
                          <div
                            onClick={(e) => {
                              if (hasChildren) {
                                toggleMobileDropdown(index, e);
                              } else {
                                handleLinkClick(index, item.href, e);
                              }
                            }}
                            className={`flex-1 cursor-pointer transition-all duration-300 px-6 py-4 ${isActive
                              ? "bg-[linear-gradient(127deg,rgb(18,212,255)_0%,rgb(25,89,250)_100%)] [-webkit-background-clip:text] [-webkit-text-fill-color:transparent] bg-clip-text [font-family:'Be_Vietnam_Pro',Helvetica] font-medium text-base tracking-[0] leading-[normal]"
                              : "[font-family:'Be_Vietnam_Pro',Helvetica] font-normal text-[#4d4d4d] text-base tracking-[0] leading-[normal] hover:text-[#666666]"
                              }`}
                          >
                            {item.label}
                          </div>
                          {hasChildren && (
                            <button
                              type="button"
                              onClick={(e) => toggleMobileDropdown(index, e)}
                              className="px-4 py-4 text-[#4d4d4d] hover:text-[#666666] transition-colors"
                              aria-label={isExpanded ? "Collapse" : "Expand"}
                            >
                              <ChevronDown
                                className={`w-5 h-5 transition-transform duration-300 ${isExpanded ? "rotate-180" : ""
                                  }`}
                              />
                            </button>
                          )}
                        </div>

                        {/* Active indicator for mobile */}
                        {isActive && !hasChildren && (
                          <div
                            className="absolute left-0 top-0 bottom-0 w-[4px] transition-all duration-300"
                            style={{
                              background: "linear-gradient(180deg, #12D4FF 22.22%, #1959FA 88.58%)",
                            }}
                          />
                        )}

                        {/* Mobile Dropdown Children */}
                        {hasChildren && (
                          <AnimatePresence>
                            {isExpanded && (
                              <motion.div
                                initial={{ height: 0, opacity: 0 }}
                                animate={{ height: "auto", opacity: 1 }}
                                exit={{ height: 0, opacity: 0 }}
                                transition={{ duration: 0.3 }}
                                className="overflow-hidden"
                              >
                                <div className="bg-gray-50">
                                  {item.children?.map((child, childIndex) => (
                                    <div
                                      key={childIndex}
                                      onClick={(e) => handleChildClick(child.href, e)}
                                      className="px-12 py-3 text-sm text-[#4d4d4d] hover:bg-gray-100 hover:text-[#1959FA] cursor-pointer transition-colors duration-200 [font-family:'Be_Vietnam_Pro',Helvetica]"
                                    >
                                      {child.label}
                                    </div>
                                  ))}
                                </div>
                              </motion.div>
                            )}
                          </AnimatePresence>
                        )}
                      </div>
                    );
                  })}
                </div>
              </div>

              {/* Mobile Get a quote button */}
              <div className="p-4 border-t border-gray-200">
                <motion.button
                  type="button"
                  onClick={(e) => {
                    e.preventDefault();
                    setIsMobileMenuOpen(false);
                    router.push("/legal/contact-us");
                  }}
                  className="w-full bg-[linear-gradient(33deg,rgb(18,212,255)_0%,rgb(25,89,250)_100%)] text-white px-6 py-3 rounded-md font-poppins text-base font-medium hover:opacity-90 transition"
                  whileHover={buttonHover}
                  whileTap={buttonTap}
                >
                  Get a quote
                </motion.button>
              </div>
            </div>
          </div>
        </>
      )}
    </nav>
  );
}

"use client";

import React, { useState, useEffect, useCallback, useMemo } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { X, ChevronDown, Filter, MapPin, RotateCcw } from "lucide-react";
import {
    JobFilters,
    JobCategory,
    WorkMode,
    EmploymentType,
    categoryLabels,
    workModeLabels,
    employmentTypeLabels,
    distanceOptions,
} from "@/lib/jobs/jobTypes";

interface FilterPanelProps {
    filters: JobFilters;
    onFiltersChange: (filters: JobFilters) => void;
    onClearFilters: () => void;
    jobCount: number;
    isMobileOpen?: boolean;
    onMobileClose?: () => void;
}

export default function FilterPanel({
    filters,
    onFiltersChange,
    onClearFilters,
    jobCount,
    isMobileOpen = false,
    onMobileClose,
}: FilterPanelProps) {
    const [expandedSections, setExpandedSections] = useState<Record<string, boolean>>({
        location: true,
        category: true,
        workMode: true,
        employmentType: true,
    });

    const toggleSection = useCallback((section: string) => {
        setExpandedSections((prev) => ({ ...prev, [section]: !prev[section] }));
    }, []);

    const updateFilter = useCallback(<K extends keyof JobFilters>(key: K, value: JobFilters[K]) => {
        onFiltersChange({ ...filters, [key]: value });
    }, [filters, onFiltersChange]);

    const toggleArrayFilter = useCallback(<T extends string>(
        key: "categories" | "workModes" | "employmentTypes",
        value: T
    ) => {
        const current = filters[key] as T[];
        const updated = current.includes(value)
            ? current.filter((v) => v !== value)
            : [...current, value];
        updateFilter(key, updated as JobFilters[typeof key]);
    }, [filters, updateFilter]);

    const hasActiveFilters = useMemo(() =>
        filters.location !== "" ||
        filters.categories.length > 0 ||
        filters.workModes.length > 0 ||
        filters.employmentTypes.length > 0,
        [filters]);

    // Filter content as JSX (not a component to avoid re-creation)
    const filterContent = (
        <div className="space-y-6">
            {/* Location & Distance */}
            <FilterSection
                title="Location"
                isExpanded={expandedSections.location}
                onToggle={() => toggleSection("location")}
            >
                <div className="space-y-3">
                    <div className="relative">
                        <MapPin className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                        <input
                            type="text"
                            placeholder="City or location"
                            value={filters.location}
                            onChange={(e) => updateFilter("location", e.target.value)}
                            className="w-full pl-10 pr-4 py-2.5 bg-gray-50 border border-gray-200 rounded-lg text-sm outline-none focus:border-[#12D4FF] focus:ring-1 focus:ring-[#12D4FF]/20 transition-all"
                            aria-label="Filter by location"
                        />
                    </div>
                    <div>
                        <label className="text-xs text-gray-500 mb-1 block">Distance (km)</label>
                        <select
                            value={filters.distance}
                            onChange={(e) => updateFilter("distance", Number(e.target.value))}
                            className="w-full px-3 py-2.5 bg-gray-50 border border-gray-200 rounded-lg text-sm outline-none focus:border-[#12D4FF] transition-all cursor-pointer"
                            aria-label="Filter by distance"
                        >
                            {distanceOptions.map((d) => (
                                <option key={d} value={d}>
                                    Within {d} km
                                </option>
                            ))}
                        </select>
                    </div>
                </div>
            </FilterSection>

            {/* Job Category */}
            <FilterSection
                title="Job Category"
                isExpanded={expandedSections.category}
                onToggle={() => toggleSection("category")}
                count={filters.categories.length}
            >
                <div className="space-y-2">
                    {(Object.keys(categoryLabels) as JobCategory[]).map((cat) => (
                        <CheckboxItem
                            key={cat}
                            label={categoryLabels[cat]}
                            checked={filters.categories.includes(cat)}
                            onChange={() => toggleArrayFilter("categories", cat)}
                        />
                    ))}
                </div>
            </FilterSection>

            {/* Work Mode */}
            <FilterSection
                title="Work Mode"
                isExpanded={expandedSections.workMode}
                onToggle={() => toggleSection("workMode")}
                count={filters.workModes.length}
            >
                <div className="space-y-2">
                    {(Object.keys(workModeLabels) as WorkMode[]).map((mode) => (
                        <CheckboxItem
                            key={mode}
                            label={workModeLabels[mode]}
                            checked={filters.workModes.includes(mode)}
                            onChange={() => toggleArrayFilter("workModes", mode)}
                        />
                    ))}
                </div>
            </FilterSection>

            {/* Employment Type */}
            <FilterSection
                title="Employment Type"
                isExpanded={expandedSections.employmentType}
                onToggle={() => toggleSection("employmentType")}
                count={filters.employmentTypes.length}
            >
                <div className="space-y-2">
                    {(Object.keys(employmentTypeLabels) as EmploymentType[]).map((type) => (
                        <CheckboxItem
                            key={type}
                            label={employmentTypeLabels[type]}
                            checked={filters.employmentTypes.includes(type)}
                            onChange={() => toggleArrayFilter("employmentTypes", type)}
                        />
                    ))}
                </div>
            </FilterSection>

            {/* Clear Filters */}
            {hasActiveFilters && (
                <button
                    onClick={onClearFilters}
                    className="w-full flex items-center justify-center gap-2 py-2.5 text-sm font-medium text-gray-600 bg-gray-100 hover:bg-gray-200 rounded-lg transition-colors"
                >
                    <RotateCcw className="w-4 h-4" />
                    Clear All Filters
                </button>
            )}
        </div>
    );

    // Render both layouts, use CSS to show/hide based on screen size
    return (
        <>
            {/* Mobile Drawer */}
            <AnimatePresence>
                {isMobileOpen && (
                    <>
                        {/* Backdrop */}
                        <motion.div
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            exit={{ opacity: 0 }}
                            className="fixed inset-0 bg-black/50 z-40 lg:hidden"
                            onClick={onMobileClose}
                        />
                        {/* Drawer */}
                        <motion.div
                            initial={{ x: "-100%" }}
                            animate={{ x: 0 }}
                            exit={{ x: "-100%" }}
                            transition={{ type: "spring", damping: 25, stiffness: 300 }}
                            className="fixed top-0 left-0 h-full w-[320px] max-w-[85vw] bg-white z-50 lg:hidden shadow-2xl"
                        >
                            {/* Header */}
                            <div className="flex items-center justify-between p-4 border-b border-gray-100">
                                <div className="flex items-center gap-2">
                                    <Filter className="w-5 h-5 text-[#1959FA]" />
                                    <span className="font-semibold text-gray-900">Filters</span>
                                    <span className="text-sm text-gray-500">({jobCount} jobs)</span>
                                </div>
                                <button
                                    onClick={onMobileClose}
                                    className="p-2 hover:bg-gray-100 rounded-lg transition-colors"
                                    aria-label="Close filters"
                                >
                                    <X className="w-5 h-5 text-gray-500" />
                                </button>
                            </div>
                            {/* Content */}
                            <div className="p-4 overflow-y-auto h-[calc(100%-60px)]">
                                {filterContent}
                            </div>
                        </motion.div>
                    </>
                )}
            </AnimatePresence>

            {/* Desktop Sidebar - use CSS lg:block to show only on desktop */}
            <div className="hidden lg:block w-[280px] flex-shrink-0">
                <div className="sticky top-[160px] bg-white rounded-xl border border-gray-100 p-5 shadow-sm">
                    <div className="flex items-center justify-between mb-5">
                        <div className="flex items-center gap-2">
                            <Filter className="w-5 h-5 text-[#1959FA]" />
                            <span className="font-semibold text-gray-900">Filters</span>
                        </div>
                        <span className="text-sm text-gray-500">{jobCount} jobs</span>
                    </div>
                    {filterContent}
                </div>
            </div>
        </>
    );
}

// Filter Section Component - memoized to prevent re-renders
const FilterSection = React.memo(function FilterSection({
    title,
    children,
    isExpanded,
    onToggle,
    count,
}: {
    title: string;
    children: React.ReactNode;
    isExpanded: boolean;
    onToggle: () => void;
    count?: number;
}) {
    return (
        <div className="border-b border-gray-100 pb-4 last:border-0 last:pb-0">
            <button
                onClick={onToggle}
                className="w-full flex items-center justify-between py-2 text-left"
                aria-expanded={isExpanded}
            >
                <span className="font-medium text-gray-800 text-sm flex items-center gap-2">
                    {title}
                    {count && count > 0 && (
                        <span className="bg-[#12D4FF]/10 text-[#1959FA] text-xs px-2 py-0.5 rounded-full">
                            {count}
                        </span>
                    )}
                </span>
                <ChevronDown
                    className={`w-4 h-4 text-gray-400 transition-transform ${isExpanded ? "rotate-180" : ""}`}
                />
            </button>
            <AnimatePresence initial={false}>
                {isExpanded && (
                    <motion.div
                        initial={{ height: 0, opacity: 0 }}
                        animate={{ height: "auto", opacity: 1 }}
                        exit={{ height: 0, opacity: 0 }}
                        transition={{ duration: 0.2 }}
                        className="overflow-hidden"
                    >
                        <div className="pt-2">{children}</div>
                    </motion.div>
                )}
            </AnimatePresence>
        </div>
    );
});

// Checkbox Item Component - memoized to prevent re-renders
const CheckboxItem = React.memo(function CheckboxItem({
    label,
    checked,
    onChange,
}: {
    label: string;
    checked: boolean;
    onChange: () => void;
}) {
    return (
        <label className="flex items-center gap-3 py-1.5 cursor-pointer group">
            <div
                className={`w-5 h-5 rounded border-2 flex items-center justify-center transition-all ${checked
                        ? "bg-[#1959FA] border-[#1959FA]"
                        : "border-gray-300 group-hover:border-[#12D4FF]"
                    }`}
            >
                {checked && (
                    <svg className="w-3 h-3 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
                    </svg>
                )}
            </div>
            <input
                type="checkbox"
                checked={checked}
                onChange={onChange}
                className="sr-only"
                aria-label={label}
            />
            <span className="text-sm text-gray-600 group-hover:text-gray-900 transition-colors">
                {label}
            </span>
        </label>
    );
});

