"use client";

import { motion, useInView, useMotionValue, useSpring, animate } from "framer-motion";
import { useEffect, useRef, useState } from "react";
import { staggerContainer, fadeUp, viewportOnce } from "@/animations";

function Counter({ value, label }: { value: string; label: string }) {
  const ref = useRef<HTMLDivElement>(null);
  const isInView = useInView(ref, { once: true, amount: 0.5 });
  const [displayValue, setDisplayValue] = useState(0);
  
  // Extract numeric value for animation
  const numericValue = parseInt(value.replace(/[^0-9]/g, "")) || 0;
  const prefix = value.startsWith("+") ? "+" : "";
  const hasComma = value.includes(",");

  useEffect(() => {
    if (isInView) {
      const controls = animate(0, numericValue, {
        duration: 2,
        ease: [0.6, -0.05, 0.01, 0.99],
        onUpdate: (latest) => {
          setDisplayValue(Math.round(latest));
        },
      });
      return controls.stop;
    }
  }, [isInView, numericValue]);

  const formatNumber = (num: number) => {
    if (hasComma && num >= 1000) {
      return num.toLocaleString();
    }
    return num.toString();
  };

  return (
    <motion.div
      ref={ref}
      className="text-center"
      variants={fadeUp}
      initial="hidden"
      animate={isInView ? "show" : "hidden"}
    >
      <div className="text-3xl sm:text-4xl md:text-5xl lg:text-6xl font-bold text-[#0A0A0A] mb-2 sm:mb-3 leading-none">
        {prefix}{formatNumber(displayValue)}
      </div>
      <div className="text-xs sm:text-sm md:text-base font-medium text-[#6B7280] uppercase tracking-wide">
        {label}
      </div>
    </motion.div>
  );
}

export default function Stats() {
  const stats = [
    { value: "+10", label: "AWARDS" },
    { value: "+190", label: "CASE STUDIES" },
    { value: "+2,781", label: "CUSTOMERS" },
    { value: "4", label: "OFFICES" },
  ];

  return (
    <motion.section
      className="py-12 sm:py-16 md:py-20 lg:py-24 px-4 sm:px-6 md:px-8 bg-[#ECF9FB]"
      initial="hidden"
      whileInView="show"
      viewport={viewportOnce}
    >
      <div className="container max-w-[1200px] mx-auto">
        <motion.div
          className="grid grid-cols-2 md:grid-cols-4 gap-6 sm:gap-8 md:gap-12"
          variants={staggerContainer}
        >
          {stats.map((stat, index) => (
            <Counter key={index} value={stat.value} label={stat.label} />
          ))}
        </motion.div>
      </div>
    </motion.section>
  );
}

