                className="border border-white/80 text-white text-xs sm:text-sm md:text-base font-semibold px-5 sm:px-6 md:px-8 py-2.5 sm:py-3 md:py-[17px] rounded-[6px] hover:bg-white/10 transition-colors min-h-[44px] touch-manipulation inline-flex items-center justify-center"
                whileHover={{ scale: 1.05 }}
                whileTap={{ scale: 0.95 }}
              >
                Talk to an Expert
              </motion.a>
            </motion.div>
          </div>
        </div>
      </div>
    </section>
  );
}

